    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xAA8817E28C993243ULL + 0xC64E43D0A05A157BULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xF682C3BEFA15A423ULL + 0xB662B69B0F4749D7ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0x99638D5D2FA22CE9ULL + 0xB02B1D1CC8350622ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0xD9BF5D9803181E97ULL + 0x9B7B00618EFF41B5ULL);
