            aOrbiterE = (((aWandererC + RotL64(aPrevious, 53U)) + RotL64(aCarry, 47U)) + 15935192152535800515U) + aOrbiterAssignSaltD[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterD = (aWandererJ + RotL64(aIngress, 11U)) + 16029480584184621035U;
