            aOrbiterD = ((aOrbiterD + aOrbiterI) + 11939455624694015579U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 22U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 12878781065107157258U;
