            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 9140887959975924330U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterB) ^ 1064043884193485266U;
            aOrbiterJ = RotL64((aOrbiterJ * 5741907199983926781U), 39U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterA) + 11881452504973661393U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 17532310360233460518U;
            aOrbiterD = RotL64((aOrbiterD * 9676965784886691377U), 21U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterK) + 16511707518680610375U) + aNonceWordH;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 1672755433824243399U;
            aOrbiterI = RotL64((aOrbiterI * 9443142203015435713U), 41U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterE) + 11327194927630035559U;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 12814066356460945863U;
