            aOrbiterA = RotL64((aOrbiterA * 3521640948740631263U), 27U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterC) + 16772051586271850014U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterJ) ^ 457329220611976094U;
            aOrbiterG = RotL64((aOrbiterG * 13646138198821165621U), 19U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterH) + 4984438271143649513U) + aNonceWordB;
