            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererD = aWandererD + ((((RotL64(aScatter, 35U) + RotL64(aOrbiterF, 30U)) + aOrbiterD) + RotL64(aCarry, 11U)) + aNonceWordJ);
            aWandererH = aWandererH ^ ((((RotL64(aPrevious, 53U) + aOrbiterB) + RotL64(aOrbiterC, 35U)) + aNonceWordP) + aWandererUpdateSaltD[(((31U - aIndex) + 19U)) & S_SALT1]);
            aWandererG = aWandererG + (((RotL64(aIngress, 58U) + aOrbiterC) + RotL64(aOrbiterA, 43U)) + aWandererUpdateSaltE[((aIndex + 13U)) & S_SALT1]);
