            //
            aOrbiterG = ((aOrbiterG + aOrbiterK) + 2612560041967631466U) + aOrbiterUpdateSaltE[((aIndex + 5U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 9339287729897403182U;
